import { useNavigate } from 'react-router-dom';
import ThemeToggle from '../components/common/ThemeToggle';

export default function Welcome() {
  const navigate = useNavigate();

  const roles = [
    {
      id: 'user',
      title: 'Borrower',
      desc: 'Apply for loans with instant AI-powered decisions',
      icon: '👤',
      action: 'Start as Borrower',
      color: '#2563eb',
      path: '/register/user'
    },
    {
      id: 'officer',
      title: 'Loan Officer',
      desc: 'Review and manage loan applications professionally',
      icon: '👨‍💼',
      action: 'Loan Officer Access',
      color: '#059669',
      path: '/register/officer'
    },
    {
      id: 'admin',
      title: 'Administrator',
      desc: 'Enterprise-level portfolio management & analytics',
      icon: '⚙️',
      action: 'Admin Portal',
      color: '#4f46e5',
      path: '/register/admin'
    },
  ];

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, var(--bg-page), var(--clr-slate-50))',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: 'var(--space-6)',
      position: 'relative',
    }}>
      <div style={{ position: 'absolute', top: 20, right: 20 }}>
        <ThemeToggle size="small" />
      </div>

      <div style={{ maxWidth: 1200, width: '100%' }}>
        <div style={{ textAlign: 'center', marginBottom: 'var(--space-16)' }}>
          <div style={{ fontSize: 60, marginBottom: 'var(--space-4)' }}>🛡️</div>
          <h1 style={{
            fontSize: 'var(--font-size-4xl)',
            fontWeight: 800,
            color: 'var(--text-primary)',
            marginBottom: 'var(--space-4)',
            letterSpacing: '-0.03em',
          }}>
            LoanGuard
          </h1>
          <p style={{
            fontSize: 'var(--font-size-md)',
            color: 'var(--text-secondary)',
            maxWidth: 500,
            margin: '0 auto',
            lineHeight: 1.6,
          }}>
            AI-powered loan decision platform. Choose your role and get started in minutes.
          </p>
        </div>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
          gap: 'var(--space-8)',
          marginBottom: 'var(--space-12)',
        }}>
          {roles.map(role => (
            <div
              key={role.id}
              onClick={() => navigate(role.path)}
              style={{
                padding: 'var(--space-8)',
                borderRadius: 'var(--border-radius-lg)',
                background: 'var(--bg-card)',
                border: `2px solid ${role.color}22`,
                cursor: 'pointer',
                transition: 'all var(--transition-base)',
                position: 'relative',
                overflow: 'hidden',
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.boxShadow = `0 12px 24px ${role.color}22`;
                e.currentTarget.style.borderColor = role.color;
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'var(--shadow-sm)';
                e.currentTarget.style.borderColor = `${role.color}22`;
              }}
            >
              <div style={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                height: 3,
                background: role.color,
              }} />

              <div style={{ fontSize: 40, marginBottom: 'var(--space-4)' }}>
                {role.icon}
              </div>

              <h2 style={{
                fontSize: 'var(--font-size-lg)',
                fontWeight: 700,
                color: 'var(--text-primary)',
                marginBottom: 'var(--space-2)',
              }}>
                {role.title}
              </h2>

              <p style={{
                fontSize: 'var(--font-size-sm)',
                color: 'var(--text-secondary)',
                lineHeight: 1.6,
                marginBottom: 'var(--space-6)',
              }}>
                {role.desc}
              </p>

              <button
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: 'var(--space-2)',
                  padding: 'var(--space-3) var(--space-6)',
                  borderRadius: 'var(--border-radius-md)',
                  background: role.color,
                  color: 'white',
                  fontWeight: 600,
                  fontSize: 'var(--font-size-sm)',
                  border: 'none',
                  cursor: 'pointer',
                  transition: 'all var(--transition-fast)',
                }}
                onClick={() => navigate(role.path)}
                onMouseEnter={(e) => {
                  e.currentTarget.style.opacity = 0.9;
                  e.currentTarget.style.transform = 'translateX(4px)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.opacity = 1;
                  e.currentTarget.style.transform = 'translateX(0)';
                }}
              >
                {role.action}
                <span style={{ fontSize: 18 }}>→</span>
              </button>

              <div style={{ marginTop: 'var(--space-6)', paddingTop: 'var(--space-4)', borderTop: '1px solid var(--border-default)' }}>
                <p style={{ fontSize: 'var(--font-size-xs)', color: 'var(--text-muted)', margin: 0 }}>
                  Already have an account?{' '}
                  <button
                    style={{
                      background: 'none',
                      border: 'none',
                      color: role.color,
                      fontWeight: 600,
                      cursor: 'pointer',
                      padding: 0,
                    }}
                    onClick={(e) => {
                      e.stopPropagation();
                      navigate('/login');
                    }}
                  >
                    Sign in
                  </button>
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
